description:
Implement the main entry point:

```go
// main.go
package main

import (
    "flag"
    "fmt"
    "os"
    "time"
)

func main() {
    // CRITICAL: Capture input FIRST before any other I/O
    // This is what fixes the bash race condition
    var inputContext string
    var inputErr error

    // Check for help/version before input capture
    if len(os.Args) > 1 && (os.Args[1] == "-h" || os.Args[1] == "--help") {
        printUsage()
        os.Exit(0)
    }

    // Parse positional args first to get file list
    if len(os.Args) < 3 {
        fmt.Fprintln(os.Stderr, "Error: Missing protocol or instruction")
        printUsage()
        os.Exit(1)
    }

    protocolName := os.Args[1]
    instruction := os.Args[2]
    fileArgs := os.Args[3:]

    // Filter out flags from file args
    var files []string
    fs := flag.NewFlagSet("gemini-slave", flag.ContinueOnError)
    outputFormat := fs.String("o", "", "Output format: text, json, stream-json")
    fs.String("output-format", "", "Output format (alias)")
    modelOverride := fs.String("m", "", "Override model")
    fs.String("model", "", "Model override (alias)")
    timeoutSec := fs.Int("t", 0, "Timeout in seconds")
    fs.Int("timeout", 0, "Timeout (alias)")
    verbose := fs.Bool("v", false, "Verbose output")
    fs.Bool("verbose", false, "Verbose (alias)")

    // Parse flags, remaining are files
    fs.Parse(fileArgs)
    files = fs.Args()

    // NOW capture input (stdin or files)
    inputContext, inputErr = CaptureInput(files)
    if inputErr != nil {
        fmt.Fprintf(os.Stderr, "Error: %v\n", inputErr)
        os.Exit(1)
    }

    // Load protocol
    protocol, err := LoadProtocol(protocolName)
    if err != nil {
        if protocolName == "scout" {
            fmt.Fprintln(os.Stderr, "⚠️  WARNING: scout protocol is deprecated")
            fmt.Fprintln(os.Stderr, "   Use 'gogent-scout' for file metrics")
            fmt.Fprintln(os.Stderr, "   Use 'gemini-slave mapper' for semantic analysis")
        }
        fmt.Fprintf(os.Stderr, "Error: %v\n", err)
        fmt.Fprintln(os.Stderr, "\nAvailable protocols:")
        if protos, err := ListProtocols(); err == nil {
            for _, p := range protos {
                fmt.Fprintf(os.Stderr, "  %s\n", p)
            }
        }
        os.Exit(1)
    }

    // Apply overrides
    model := protocol.Model
    if envModel := os.Getenv("GEMINI_MODEL"); envModel != "" {
        model = envModel
    }
    if *modelOverride != "" {
        model = *modelOverride
    }

    timeout := protocol.Timeout
    if *timeoutSec > 0 {
        timeout = time.Duration(*timeoutSec) * time.Second
    }

    outFmt := ""
    if *outputFormat != "" {
        outFmt = *outputFormat
    } else if protocol.OutputJSON {
        outFmt = "json"
    }

    // Build prompt
    prompt := fmt.Sprintf("%s\n\n---\n### SPECIFIC INSTRUCTION\n%s\n\n---\n### INPUT CONTEXT\n%s",
        protocol.Content, instruction, inputContext)

    // Execute
    exec := &Executor{
        Model:        model,
        OutputFormat: outFmt,
        Timeout:      timeout,
        Verbose:      *verbose,
    }

    output, err := exec.Execute(prompt)
    if err != nil {
        fmt.Fprintf(os.Stderr, "Error: %v\n", err)
        os.Exit(1)
    }

    fmt.Print(output)
}

func printUsage() {
    fmt.Println(`Usage: gemini-slave <protocol> "instruction" [files...] [options]

Options:
  -o, --output-format   Output format: text, json, stream-json
  -m, --model           Override model selection
  -t, --timeout         Override timeout in seconds
  -v, --verbose         Show debug information
  -h, --help            Show help

Environment:
  GEMINI_MODEL          Override model for all protocols

Examples:
  # Pipe code to mapper
  find cmd/ -name "*.go" -exec cat {} \; | gemini-slave mapper "Map entry points"

  # Pass files directly
  gemini-slave deps "Extract deps" cmd/*.go

  # Force JSON output
  gemini-slave architect "Review" -o json < module.go`)
}
